import{_ as a,b as o,o as r,i as d,j as i,g as n,aB as l}from"./chunks/framework._ZAOES46.js";const k=JSON.parse('{"title":"FaIconPicker 图标选择器","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaIconPicker.md","filePath":"components/pro/FaIconPicker.md"}'),c={name:"components/pro/FaIconPicker.md"};function s(h,e,p,m,b,f){const t=o("Badge");return r(),d("div",null,[e[0]||(e[0]=i("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaIconPicker.md for this page in Markdown format",-1)),n(t,{type:"pro",text:"专业版"}),e[1]||(e[1]=l('<h1 id="faiconpicker-图标选择器" tabindex="-1">FaIconPicker 图标选择器 <a class="header-anchor" href="#faiconpicker-图标选择器" aria-label="Permalink to “FaIconPicker 图标选择器”">​</a></h1><p>从 Iconify 图标库中选择图标的选择器组件，支持搜索和分类浏览。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>菜单图标配置</li><li>按钮图标选择</li><li>表单字段图标</li><li>标签页图标</li><li>导航图标设置</li><li>状态图标配置</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><h3 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to “Model”">​</a></h3><table tabindex="0"><thead><tr><th>名称</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>modelValue</code></td><td><code>string</code></td><td>选中的图标名称</td></tr><tr><td><code>icons</code></td><td><code>IconPickerCollection[]</code></td><td>图标集合数据</td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td><code>default</code></td><td>自定义触发器，slot props: <code>{ icon: string }</code></td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><strong>图标格式</strong>：选中的图标格式为 <code>前缀：图标名</code>，如 <code>i-lucide:home</code></li><li><strong>图标来源</strong>：图标来自项目配置的 Iconify 图标集</li><li><strong>搜索功能</strong>：支持在弹窗内搜索图标</li><li><strong>分类浏览</strong>：左侧显示图标集分类，右侧显示具体图标</li><li><strong>分页加载</strong>：每个图标集分页显示，支持翻页</li></ol><h2 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to “注意”">​</a></h2><p>使用该组件前，先执行 <code>pnpm run -F &lt;app&gt; generate:icons</code> 命令，并按照指引完成操作后，图标选择器才能正常显示需要的图标集。</p>',13))])}const _=a(c,[["render",s]]);export{k as __pageData,_ as default};
